const items = $input.all();

// ── Repair stray literal "\n" / "\r" formatting artifacts ──────────────────
// n8n's form/textarea sometimes submits JSON where line breaks between
// tokens come through as the two literal characters backslash+n (or
// backslash+r) instead of an actual newline byte. This breaks JSON.parse
// even though the data itself is otherwise fine.
//
// This only strips those literal sequences OUTSIDE of quoted strings, so a
// node's "jsCode" or message HTML that legitimately contains \n as part of
// its value is left completely untouched.
function stripStructuralEscapes(text) {
  let result = '';
  let inString = false;

  for (let i = 0; i < text.length; i++) {
    const char = text[i];

    if (inString) {
      if (char === '\\' && i + 1 < text.length) {
        result += char + text[i + 1];
        i++;
        continue;
      }
      if (char === '"') inString = false;
      result += char;
      continue;
    }

    if (char === '"') {
      inString = true;
      result += char;
      continue;
    }

    if (char === '\\' && (text[i + 1] === 'n' || text[i + 1] === 'r')) {
      i++; // drop both characters of the stray escape sequence
      continue;
    }

    result += char;
  }

  return result;
}

function parseWithRepair(rawText) {
  try {
    return { parsed: JSON.parse(rawText), error: null };
  } catch (firstError) {
    try {
      const repaired = stripStructuralEscapes(rawText);
      return { parsed: JSON.parse(repaired), error: null };
    } catch (secondError) {
      return { parsed: null, error: firstError };
    }
  }
}

for (const item of items) {
  const rawText = item.json["Workflow JSON"];
  delete item.json["Workflow JSON"];

  // ── 1. Parse the JSON (with repair fallback) ────────────────────────────
  const { parsed, error } = parseWithRepair(rawText);

  if (!parsed) {
    item.json.success = false;
    item.json.errors  = [`Invalid JSON syntax: ${error.message}`];
    item.json.message = "Workflow JSON failed — could not parse JSON";
    continue;
  }

  // ── 2. Validate n8n workflow format ─────────────────────────────────────
  const errors   = [];
  const warnings = [];

  // ── 2a. Top-level required fields ───────────────────────────────────────
  // NOTE: "name" is NOT required for n8n import — n8n assigns one if missing
  const requiredTopLevel = ["nodes", "connections"];
  for (const field of requiredTopLevel) {
    if (!(field in parsed)) {
      errors.push(`Missing required top-level field: "${field}"`);
    }
  }

  if (!parsed.name) {
    warnings.push('"name" field is missing (n8n will assign one on import)');
  }

  // ── 2b. nodes: must be a non-empty array ────────────────────────────────
  if (!Array.isArray(parsed.nodes)) {
    errors.push('"nodes" must be an array');
  } else if (parsed.nodes.length === 0) {
    errors.push('"nodes" array must not be empty');
  } else {
    const nodeNames = new Set();
    const nodeIds   = new Set();

    parsed.nodes.forEach((node, idx) => {
      const prefix = `nodes[${idx}] ("${node.name || 'unnamed'}")`;

      if (typeof node.name !== 'string' || node.name.trim() === '') {
        errors.push(`${prefix}: missing or empty "name"`);
      } else {
        if (nodeNames.has(node.name)) {
          errors.push(`${prefix}: duplicate node name "${node.name}"`);
        }
        nodeNames.add(node.name);
      }

      if (typeof node.type !== 'string' || node.type.trim() === '') {
        errors.push(`${prefix}: missing or empty "type"`);
      }

      if (typeof node.typeVersion !== 'number') {
        errors.push(`${prefix}: "typeVersion" must be a number`);
      }

      // position — n8n uses ARRAY [x, y], NOT object {x, y}
      if (
        !Array.isArray(node.position) ||
        node.position.length < 2 ||
        typeof node.position[0] !== 'number' ||
        typeof node.position[1] !== 'number'
      ) {
        errors.push(`${prefix}: "position" must be an array [x, y] with two numbers`);
      }

      if (node.id === undefined || node.id === null) {
        warnings.push(`${prefix}: "id" field is missing (recommended)`);
      } else if (nodeIds.has(node.id)) {
        errors.push(`${prefix}: duplicate node id "${node.id}"`);
      } else {
        nodeIds.add(node.id);
      }
    });

    // ── 2c. connections: referenced node names must exist in nodes ───────
    if (parsed.connections && typeof parsed.connections === 'object') {
      const nodeNameSet = new Set(
        parsed.nodes.map(n => n.name).filter(Boolean)
      );

      for (const sourceName of Object.keys(parsed.connections)) {
        if (!nodeNameSet.has(sourceName)) {
          errors.push(`connections: source node "${sourceName}" does not exist in nodes array`);
        }

        const outputGroups = parsed.connections[sourceName];
        if (outputGroups && typeof outputGroups === 'object') {
          for (const outputType of Object.keys(outputGroups)) {
            const outputBranches = outputGroups[outputType];
            if (Array.isArray(outputBranches)) {
              outputBranches.forEach((branch, bi) => {
                if (Array.isArray(branch)) {
                  branch.forEach((conn, ci) => {
                    if (conn && conn.node && !nodeNameSet.has(conn.node)) {
                      errors.push(
                        `connections["${sourceName}"]["${outputType}"][${bi}][${ci}]: ` +
                        `target node "${conn.node}" does not exist in nodes array`
                      );
                    }
                  });
                }
              });
            }
          }
        }
      }
    } else if (typeof parsed.connections !== 'object') {
      errors.push('"connections" must be an object');
    }
  }

  // ── 2d. Optional field warnings ─────────────────────────────────────────
  if (!parsed.settings || typeof parsed.settings !== 'object') {
    warnings.push('"settings" field is missing (recommended)');
  }

  // ── 3. Attach result + the clean workflow JSON ──────────────────────────
  item.json.workflowJson = parsed;

  if (errors.length === 0) {
    item.json.success  = true;
    item.json.errors   = [];
    item.json.warnings = warnings;
    item.json.message  = "Workflow JSON is valid and ready to import into n8n";
  } else {
    item.json.success  = false;
    item.json.errors   = errors;
    item.json.warnings = warnings;
    item.json.message  = `Workflow JSON failed validation with ${errors.length} error(s)`;
  }
}

return items;

